def simulate_arrows(apollo_affected, daphne_affected):
    # Golden arrow: causes love (True if affected, False otherwise)
    # Leaden arrow: prevents love (True if affected, False otherwise)
    return {
        "Apollo": "Falls in love with Daphne" if apollo_affected else "Indifferent to Daphne",
        "Daphne": "Unable to love Apollo" if daphne_affected else "Capable of loving Apollo"
    }

# Example usage:
print(simulate_arrows(True, True))  # Apollo loves, Daphne cannot reciprocate
